from dataclasses import dataclass, field
from typing import Any


@dataclass
class BeliefState:
    """
    Tracks what the agent BELIEVES about the world when the
    environment is only partially observable.
    Each belief has a confidence value 0..1.
    """
    beliefs: dict[str, Any] = field(default_factory=dict)
    confidences: dict[str, float] = field(default_factory=dict)

    def update(self, key: str, value: Any, confidence: float = 1.0) -> None:
        self.beliefs[key] = value
        self.confidences[key] = max(0.0, min(1.0, confidence))

    def get(self, key: str, default: Any = None) -> Any:
        return self.beliefs.get(key, default)

    def decay(self, factor: float = 0.95) -> None:
        """Reduce confidence in all beliefs over time (world may have changed)."""
        for k in self.confidences:
            self.confidences[k] *= factor


class PartiallyObservableAgent:
    """Agent for a partially observable environment: maintains a belief state."""

    def __init__(self):
        self.belief_state = BeliefState()

    def observe(self, percept: dict[str, Any]) -> None:
        """Update beliefs from partial percept."""
        for key, value in percept.items():
            self.belief_state.update(key, value, confidence=0.9)
        # Decay unseen beliefs (things might have changed)
        self.belief_state.decay()

    def act(self) -> str:
        location = self.belief_state.get("robot_location", "unknown")
        battery  = self.belief_state.get("battery_level", 100)
        if battery < 20:
            return "return_to_charger"
        if location == "unknown":
            return "localise"  # recover from lost state
        return "explore"


# Simulate: agent only sees partial info each step
agent = PartiallyObservableAgent()
agent.observe({"robot_location": "room_A", "battery_level": 85})
print(agent.act())  # explore

agent.observe({"battery_level": 15})  # location unseen this step
print(agent.act())  # return_to_charger

import random
from dataclasses import dataclass


@dataclass
class StochasticEnvironment:
    """Environment where actions have probabilistic outcomes."""

    def transition(self, state: int, action: str) -> int:
        """
        Returns next state. 'move_forward' succeeds 80% of the time;
        20% of the time the robot slips and stays in place.
        """
        if action == "move_forward":
            return state + 1 if random.random() < 0.8 else state
        if action == "move_back":
            return state - 1 if random.random() < 0.8 else state
        return state


class StochasticAgent:
    """Agent that plans with expected outcomes rather than deterministic ones."""

    def __init__(self, goal: int = 5):
        self.goal = goal
        self.state = 0
        self.steps = 0

    def act(self) -> str:
        # Simple policy: always move toward goal (accept stochasticity)
        return "move_forward" if self.state < self.goal else "stay"


env = StochasticEnvironment()
agent = StochasticAgent(goal=5)
random.seed(42)

for _ in range(20):
    action = agent.act()
    if action == "stay":
        break
    agent.state = env.transition(agent.state, action)
    agent.steps += 1

print(f"Reached goal {agent.goal} in {agent.steps} steps")  # ~6-8 (not 5 — slips happen)

from dataclasses import dataclass, field
from typing import Protocol


class AgentInterface(Protocol):
    name: str
    def observe(self, percept: dict) -> None: ...
    def act(self) -> str: ...


@dataclass
class MultiAgentEnvironment:
    """Shared environment where multiple agents interact."""

    resources: dict[str, int] = field(default_factory=lambda: {"item_A": 1, "item_B": 1})
    log: list[str] = field(default_factory=list)

    def step(self, agents: list) -> dict[str, str]:
        """Run all agents simultaneously; handle conflicts."""
        # Each agent observes and decides
        actions = {}
        for agent in agents:
            agent.observe({"resources": dict(self.resources)})
            actions[agent.name] = agent.act()

        # Resolve conflicts: if multiple agents grab the same item, only one wins
        results = {}
        claimed: set[str] = set()
        for agent_name, action in actions.items():
            if action.startswith("grab_") and action in self.resources:
                item = action[len("grab_"):]
                if item not in claimed and self.resources.get(item, 0) > 0:
                    self.resources[item] -= 1
                    claimed.add(item)
                    results[agent_name] = f"got {item}"
                else:
                    results[agent_name] = f"failed (conflict on {item})"
            else:
                results[agent_name] = "waited"

        self.log.append(str(results))
        return results


@dataclass
class GreedyAgent:
    name: str
    target: str = "item_A"
    _percept: dict = field(default_factory=dict)

    def observe(self, percept: dict) -> None:
        self._percept = percept

    def act(self) -> str:
        if self._percept.get("resources", {}).get(self.target, 0) > 0:
            return f"grab_{self.target}"
        return "wait"


env = MultiAgentEnvironment()
agents = [GreedyAgent("Alice", "item_A"), GreedyAgent("Bob", "item_A")]
result = env.step(agents)
print(result)
# One agent gets item_A; the other fails due to conflict
